/// Resolves the payload job and returns the best payload that has been built so far.
///
/// Note: Uses `WaitForPending` to block until at least one payload build completes,
/// enabling eager payload fetching without fixed delays on the consensus side.
pub async fn resolve(
    &self,
    id: PayloadId,
) -> Option<Result<T::BuiltPayload, PayloadBuilderError>> {
    self.resolve_kind(id, PayloadKind::WaitForPending).await
}

/// Returns the best payload for the given identifier.
///
/// Note: this merely returns the best payload so far and does not resolve the job.
pub async fn best_payload(
    &self,
    id: PayloadId,
) -> Option<Result<T::BuiltPayload, PayloadBuilderError>> {
    self.inner.best_payload(id).await
}
